// ── Types ──

type TimelineEvent = {
  label: string;
  year: number;
  dateLabel?: string; // free-form display date (e.g. "Spring 1968"); overrides year in all views
  layer: number;
  x: number;
  yOffset: number; // px from top of the layer band — lets events be repositioned vertically within a layer
  color: string;
  borderColor: string;
  style: 'normal' | 'italic';
  type: 'state' | 'anchor';
  width?: number;    // states only; px; undefined = auto-size to content
  endYear?: number;  // states only; when set alongside year (startYear), defines the span
  xOffsetPct?: number; // anchors only: signed offset from parent state's x (% units)
};

type Connection = {
  from: number;
  to: number;
  color: string;
  lineStyle: 'solid' | 'dashed' | 'dotted';
  width: number;
  showArrow: boolean;
  // Length (px) of the arrowhead, base-to-tip. Undefined falls back to
  // DEFAULT_ARROW_SIZE for connections saved before this field existed.
  arrowSize?: number;
  // Which edge of the source/target card the line attaches to. Undefined
  // means "auto" — pick whichever side faces the other event, as before.
  fromSide?: Side;
  toSide?: Side;
  autoLink?: boolean; // state→anchor line drawn as straight vertical at anchor's x
};

const DEFAULT_ARROW_SIZE = 8;

type Layer  = { label: string; icon?: string; color?: string };
type Column = { label: string; startYear: number; endYear: number; dateRange?: string; briefDescription?: string; description?: string; color?: string };
type Trend  = { label: string; startYear: number; endYear: number; color: string };
type Cut    = { startYear: number; endYear: number };

type CanvasLabel = {
  text: string;
  x: number;       // left edge as % of canvas width (0–100)
  y: number;       // px from top of u-timeline-wrap (covers topReserveH zone)
  width?: number;  // px; undefined = auto (height auto-fits to text)
  bgColor: string;
};

type ExportProfile = {
  id: string;
  label: string;
  ratio: number;   // width / height; 0 = native
  pxWidth: number; // render target width; 0 = native
  fontScale: number;
};

