// ── Row height ──
const LAYER_HEIGHT_DEFAULT = 120;
const LAYER_HEIGHT_MIN     = 90;

// Vertical room an event card needs within its layer band, so it can be
// dragged anywhere within the band without crossing into the row above/below.
const EVENT_TOP_MARGIN    = 12;
const EVENT_BOTTOM_MARGIN = 56;
const DEFAULT_Y_OFFSET    = 10;

// ── Canvas initial width (used as fallback before ResizeObserver fires) ──
const CANVAS_WIDTH_INIT  = 1600;

// Horizontal room kept clear at the very start/end of the timeline so an
// event sitting exactly on startYear or endYear has space to render and
// isn't crowded by the sticky layer-title gutter (start) or canvas edge (end).
const EVENT_EDGE_PADDING = 70; // px

// Approx half-height of a one-line event card, used to anchor connector
// lines to the card's top/bottom edge (rather than its side) when two
// connected events sit roughly one above the other.
const EVENT_CARD_HALF_HEIGHT = 14; // px

// ── Trend / column header register ──
const COLUMN_HEADER_H  = 26; // px — column-label row below trend register
const TREND_BAND_H     = 14; // px — uniform height for all trend bands
const TREND_REGISTER_H = 20; // px — minimum register height (fits 0–1 trends)
const TREND_SLOT_H     = TREND_BAND_H + 2; // 16px — band height + inter-slot gap

// Which edge of an event card a connection attaches to. 'auto' means: pick
// whichever side faces the other endpoint, the old default behavior.
type Side = 'top' | 'right' | 'bottom' | 'left';

type EventAnchor = { x: number; y: number; top: number; bottom: number; halfWidth?: number };

// Half the event-card width (83px / 2), used as a fallback to place
// left/right anchors when the real card hasn't been measured yet.
const CONNECTOR_HALF_WIDTH = 41;
// How far a connector "pushes out" perpendicular to its anchor edge before
// curving toward the other endpoint — gives every connection a clean,
// perpendicular departure/arrival from the card instead of a diagonal cut.
// This is now adaptive (see elbowFor below): a fixed value either looks like
// a tight hook for close cards or an under-curved near-straight line for far
// ones, so it's scaled to the gap between anchors and clamped to this range.
const CONNECTOR_ELBOW_MIN = 20;
const CONNECTOR_ELBOW_MAX = 90;
// Small explicit gap left between the anchor point and the card's real
// edge, so the line doesn't appear to touch/overlap the border.
const ANCHOR_GAP = 5;

// Vertical gap from a state card's actual bottom to the top of its anchor row.
// Big enough that the connecting stem is always clearly visible (never zero/inverted).
const ANCHOR_ROW_GAP = 20;

const BG_COLOR = '#f4ede2'; // Matches --bg-main; used for connection halo strokes and canvas background
const LABEL_COLORS: { hex: string; name: string }[] = [
  { hex: '#FFF3B0', name: 'Yellow' },
  { hex: '#FFD6A5', name: 'Peach' },
  { hex: '#CAFFBF', name: 'Mint' },
  { hex: '#9BF6FF', name: 'Sky' },
  { hex: '#BDB2FF', name: 'Lavender' },
  { hex: '#FFAFCC', name: 'Rose' },
];
const TOPICAL_BG = '#F2ECD7'; // Topical view background — matches .u-topical-area in CSS

function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

async function saveWithPicker(blob: Blob, suggestedName: string, mimeType: string, ext: string) {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  if ('showSaveFilePicker' in window) {
    try {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const handle = await (window as any).showSaveFilePicker({
        suggestedName,
        types: [{ description: 'File', accept: { [mimeType]: [ext] } }],
      });
      const writable = await handle.createWritable();
      await writable.write(blob);
      await writable.close();
      return;
    } catch (e) {
      if ((e as Error).name === 'AbortError') return;
    }
  }
  // Firefox / Safari: prompt for filename since no native save dialog exists
  const name = window.prompt('File name:', suggestedName);
  if (name === null) return; // cancelled
  downloadBlob(blob, name.endsWith(ext) ? name : name + ext);
}

function autoSide(center: { x: number; y: number }, other: { x: number; y: number }): Side {
  const dx = other.x - center.x;
  const dy = other.y - center.y;
  if (Math.abs(dx) < Math.abs(dy)) return dy > 0 ? 'bottom' : 'top';
  return dx > 0 ? 'right' : 'left';
}

function anchorOnSide(box: EventAnchor, side: Side): { x: number; y: number } {
  const centerY = (box.top + box.bottom) / 2;
  const halfWidth = box.halfWidth ?? CONNECTOR_HALF_WIDTH;
  switch (side) {
    case 'top':    return { x: box.x, y: box.top - ANCHOR_GAP };
    case 'bottom': return { x: box.x, y: box.bottom + ANCHOR_GAP };
    case 'left':   return { x: box.x - halfWidth - ANCHOR_GAP, y: centerY };
    case 'right':  return { x: box.x + halfWidth + ANCHOR_GAP, y: centerY };
  }
}

function sideNormal(side: Side): { x: number; y: number } {
  switch (side) {
    case 'top':    return { x: 0, y: -1 };
    case 'bottom': return { x: 0, y: 1 };
    case 'left':   return { x: -1, y: 0 };
    case 'right':  return { x: 1, y: 0 };
  }
}

// How far a curve should push out from one anchor before bending toward the
// other, scaled to the gap along the axis that side's normal points along
// (horizontal gap for left/right anchors, vertical gap for top/bottom ones).
// Scaling this way — rather than using a fixed distance — is what lets the
// curve read as a flowing "S" between offset cards instead of either an
// overshot loop (cards close together) or a barely-bent near-straight line
// (cards far apart).
function elbowFor(side: Side, dx: number, dy: number): number {
  const gap = (side === 'left' || side === 'right') ? Math.abs(dx) : Math.abs(dy);
  return Math.min(CONNECTOR_ELBOW_MAX, Math.max(CONNECTOR_ELBOW_MIN, gap * 0.45));
}

// Shared connector-curve geometry, used by both the live SVG render and the
// PNG export so the two stay visually identical. Each endpoint either uses
// an explicitly chosen side (fromSide/toSide) or falls back to whichever
// side faces the other event ('auto').
function getConnectorGeometry(
  from: EventAnchor, to: EventAnchor,
  fromSide?: Side, toSide?: Side
) {
  const fromCenter = { x: from.x, y: (from.top + from.bottom) / 2 };
  const toCenter   = { x: to.x,   y: (to.top   + to.bottom)   / 2 };
  const sideA = fromSide ?? autoSide(fromCenter, toCenter);
  const sideB = toSide   ?? autoSide(toCenter, fromCenter);

  const p1 = anchorOnSide(from, sideA);
  const p2 = anchorOnSide(to,   sideB);
  const n1 = sideNormal(sideA);
  const n2 = sideNormal(sideB);

  const x1 = p1.x, y1 = p1.y, x2 = p2.x, y2 = p2.y;
  const dx = x2 - x1, dy = y2 - y1;
  const elbow1 = elbowFor(sideA, dx, dy);
  const elbow2 = elbowFor(sideB, dx, dy);
  const c1x = x1 + n1.x * elbow1, c1y = y1 + n1.y * elbow1;
  const c2x = x2 + n2.x * elbow2, c2y = y2 + n2.y * elbow2;

  return { x1, y1, x2, y2, c1x, c1y, c2x, c2y, sideA, sideB };
}

// Point at t=0.5 on a cubic bezier — used to position the connection's
// edit/delete popup at the true curve midpoint (the simple endpoint average
// only works when the control points are mirror-symmetric, which isn't
// guaranteed once anchors can be pinned to arbitrary sides).
function bezierMidpoint(x1: number, y1: number, c1x: number, c1y: number, c2x: number, c2y: number, x2: number, y2: number) {
  return {
    x: (x1 + 3 * c1x + 3 * c2x + x2) / 8,
    y: (y1 + 3 * c1y + 3 * c2y + y2) / 8,
  };
}

// Greedy word-wrap for canvas text, since fillText doesn't wrap on its own.
function wrapCanvasText(ctx: CanvasRenderingContext2D, text: string, maxWidth: number): string[] {
  const words = text.split(/\s+/).filter(Boolean);
  const lines: string[] = [];
  let current = '';
  for (const word of words) {
    const test = current ? `${current} ${word}` : word;
    if (current && ctx.measureText(test).width > maxWidth) {
      lines.push(current);
      current = word;
    } else {
      current = test;
    }
  }
  if (current) lines.push(current);
  return lines.length > 0 ? lines : [text];
}

// ── Cutting points (year compression) ──
// A "cut" hides the years between startYear/endYear of the cut, replacing
// them with a fixed-width visual break ("/ /"). The functions below remap
// year <-> x% so every other piece of math (ticks, columns, trends, events)
// stays in plain percentage terms and only needs to call through here.
const CUT_GAP_PCT = 2.2; // width (in % of the timeline) reserved for each break

function sortedCuts(cuts: Cut[]) {
  return [...cuts].sort((a, b) => a.startYear - b.startYear);
}

function yearToXWithCuts(year: number, startYear: number, endYear: number, cuts: Cut[]) {
  const cs = sortedCuts(cuts);
  const totalCutSpan = cs.reduce((sum, c) => sum + (c.endYear - c.startYear), 0);
  const totalGapPct  = cs.length * CUT_GAP_PCT;
  const realSpan     = (endYear - startYear) - totalCutSpan;
  const realPct      = 100 - totalGapPct;

  let pct = 0;
  let cursor = startYear;
  for (const cut of cs) {
    const segSpan = cut.startYear - cursor;
    const segPct  = realSpan > 0 ? (segSpan / realSpan) * realPct : 0;
    if (year <= cut.startYear) {
      const within = segSpan > 0 ? (year - cursor) / segSpan : 0;
      return pct + within * segPct;
    }
    pct += segPct;
    if (year < cut.endYear) return pct + CUT_GAP_PCT / 2; // inside the cut itself
    pct += CUT_GAP_PCT;
    cursor = cut.endYear;
  }
  const segSpan = endYear - cursor;
  const segPct  = realSpan > 0 ? (segSpan / realSpan) * realPct : 0;
  const within  = segSpan > 0 ? (year - cursor) / segSpan : 0;
  return pct + within * segPct;
}

function xToYearWithCuts(xPercent: number, startYear: number, endYear: number, cuts: Cut[]) {
  const cs = sortedCuts(cuts);
  const totalCutSpan = cs.reduce((sum, c) => sum + (c.endYear - c.startYear), 0);
  const totalGapPct  = cs.length * CUT_GAP_PCT;
  const realSpan     = (endYear - startYear) - totalCutSpan;
  const realPct      = 100 - totalGapPct;

  let pct = 0;
  let cursor = startYear;
  for (const cut of cs) {
    const segSpan = cut.startYear - cursor;
    const segPct  = realSpan > 0 ? (segSpan / realSpan) * realPct : 0;
    if (xPercent <= pct + segPct) {
      const within = segPct > 0 ? (xPercent - pct) / segPct : 0;
      return cursor + within * segSpan;
    }
    pct += segPct;
    if (xPercent <= pct + CUT_GAP_PCT) {
      return (xPercent - pct) < CUT_GAP_PCT / 2 ? cut.startYear : cut.endYear;
    }
    pct += CUT_GAP_PCT;
    cursor = cut.endYear;
  }
  const segSpan = endYear - cursor;
  const segPct  = realSpan > 0 ? (segSpan / realSpan) * realPct : 0;
  const within  = segPct > 0 ? (xPercent - pct) / segPct : 0;
  return cursor + within * segSpan;
}

// Converts an event's stored year-fraction (0–100) into a CSS left position
// that's inset by EVENT_EDGE_PADDING px on both sides of the timeline, so
// events at the start/end years are never flush against the edges.
function eventLeft(xPercent: number) {
  return `calc(${EVENT_EDGE_PADDING}px + (100% - ${EVENT_EDGE_PADDING * 2}px) * ${xPercent / 100})`;
}

// Pixel equivalent of eventLeft(), for SVG connector lines and PNG export
// where we need an actual number rather than a CSS calc() string.
function eventLeftPx(xPercent: number, wrapWidthPx: number) {
  return EVENT_EDGE_PADDING + (wrapWidthPx - EVENT_EDGE_PADDING * 2) * (xPercent / 100);
}

function clampYOffset(y: number, layerHeight: number) {
  return Math.min(layerHeight - EVENT_BOTTOM_MARGIN, Math.max(EVENT_TOP_MARGIN, y));
}

// States always render at DEFAULT_Y_OFFSET unless they've been intentionally
// shifted below an overlapping state (yOffset meaningfully > DEFAULT_Y_OFFSET).
// Threshold of 30px distinguishes "slightly off from a canvas click" from "a real shift".
function stateDisplayY(yOffset: number): number {
  return yOffset > DEFAULT_Y_OFFSET + 30 ? yOffset : DEFAULT_Y_OFFSET;
}

// The year range a column's decade ticks should span. Prefers the header
// dateRange (what the reader sees, e.g. "1968-1992" or "2022-Present"); falls
// back to the column's layout startYear/endYear when no parseable range exists.
// "Present" (or any non-numeric end) resolves to the timeline's end year.
function columnTickRange(
  col: { startYear: number; endYear: number; dateRange?: string },
  timelineEndYear: number
): [number, number] {
  const m = col.dateRange?.match(/(\d{3,4})\s*[-–—]\s*(\d{3,4}|present)/i);
  if (m) {
    const start = parseInt(m[1], 10);
    const end = /^\d/.test(m[2]) ? parseInt(m[2], 10) : timelineEndYear;
    if (end > start) return [start, end];
  }
  return [col.startYear, col.endYear];
}

// How far the dot should sit from each state edge (measured to the DOT center).
const ANCHOR_DOT_INSET  = 20;  // px from state edge to dot
// Estimated half-width of the rendered anchor node (.u-event-anchor, max-width 83px).
// The node is centered at event.x via translateX(-50%), so the dot (node left + 5px)
// sits at event.x − NODE_HALF_W + 5 ≈ event.x − 41. Correcting for this keeps the dot
// visually inside the state box.
const ANCHOR_NODE_HALF_W = 41; // px  (half of max-width 83px)

// Default anchor-node max-width (mirrors .u-event-anchor / .u-event-node max-width in CSS).
const ANCHOR_NODE_MAX_W = 83; // px
// Gap kept between an anchor label's edge and its era column's boundary rule.
const ANCHOR_LABEL_PAD  = 8;   // px
// Floor so a near-boundary anchor still renders something legible rather than collapsing.
const ANCHOR_MIN_W      = 36;  // px

// Compute NODE-CENTER xOffsetPct values (% of usable timeline width, signed from
// state center) so each anchor's DOT lands at ANCHOR_DOT_INSET px from the state edge.
//   dot_x = nodeCenter − ANCHOR_NODE_HALF_W
//   1 → dot at stateLeft  + ANCHOR_DOT_INSET
//   2 → dot at stateLeft  + ANCHOR_DOT_INSET  and  stateRight − ANCHOR_DOT_INSET
//   3 → left, midpoint of (left + right), right
function anchorOffsetsForState(stateWPx: number, n: number, usablePx: number): number[] {
  if (n === 0 || usablePx <= 0) return [];
  const leftPx  = -stateWPx / 2 + ANCHOR_DOT_INSET  + ANCHOR_NODE_HALF_W;
  const rightPx =  stateWPx / 2 - ANCHOR_DOT_INSET  + ANCHOR_NODE_HALF_W;
  if (n === 1) return [leftPx  / usablePx * 100];
  if (n === 2) return [leftPx  / usablePx * 100, rightPx / usablePx * 100];
  return [leftPx / usablePx * 100, (leftPx + rightPx) / 2 / usablePx * 100, rightPx / usablePx * 100];
}

// Given a set of events (states + anchors), place auto-linked anchors at
// fixed pixel-inset positions within their parent state's box.
// Anchors are sorted by year (earliest = leftmost); up to 3 per state.
function applyAnchorFractions<T extends { type?: string; year: number; x: number; xOffsetPct?: number; width?: number }>(
  events: T[],
  connections: { from: number; to: number; autoLink?: boolean }[],
  stateXValues: Map<number, number>,
  cardWidths: (HTMLElement | null)[],
  usablePx: number,
): T[] {
  const stateAnchors = new Map<number, number[]>();
  connections.forEach(c => {
    if (!c.autoLink) return;
    if (!stateAnchors.has(c.from)) stateAnchors.set(c.from, []);
    stateAnchors.get(c.from)!.push(c.to);
  });

  const overrides = new Map<number, { x: number; xOffsetPct: number }>();
  stateAnchors.forEach((anchorIdxs, stateIdx) => {
    const sorted = [...anchorIdxs].sort((a, b) => (events[a]?.year ?? 0) - (events[b]?.year ?? 0));
    const n = Math.min(sorted.length, 3);
    const stateX = stateXValues.get(stateIdx) ?? events[stateIdx]?.x ?? 0;
    const stateWPx = events[stateIdx]?.width ?? (cardWidths[stateIdx]?.offsetWidth ?? 130);
    const offsets = anchorOffsetsForState(stateWPx, n, usablePx);
    sorted.slice(0, n).forEach((anchorIdx, k) => {
      overrides.set(anchorIdx, { x: stateX + offsets[k], xOffsetPct: offsets[k] });
    });
  });

  return events.map((e, i) => {
    if ((e.type ?? 'state') !== 'anchor') return e;
    const o = overrides.get(i);
    return o ? { ...e, ...o } : e;
  });
}

function getContrastColor(hex: string): string {
  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) return '#2a2825';
  const r = parseInt(hex.slice(1, 3), 16) / 255;
  const g = parseInt(hex.slice(3, 5), 16) / 255;
  const b = parseInt(hex.slice(5, 7), 16) / 255;
  // Relative luminance (sRGB, simplified linear approximation)
  const luminance = 0.2126 * r + 0.7152 * g + 0.0722 * b;
  return luminance > 0.45 ? '#2a2825' : '#f5f3ef';
}

// ── Sub-components ──

const Modal = ({
  onClose, title, accentColor, children
}: {
  onClose: () => void;
  title: string;
  accentColor?: string;
  children: React.ReactNode;
}) => (
  <div className="u-modal-backdrop" onMouseDown={(e) => { if (e.target === e.currentTarget) onClose(); }}>
    <div className="u-modal">
      <div className="u-modal-header">
        <div>
          <div className="u-modal-title">{title}</div>
          <div className="u-modal-stripe" style={accentColor ? { background: accentColor } : undefined} />
        </div>
        <button className="u-modal-close" onClick={onClose}><MSIcon n="close" size={16} /></button>
      </div>
      {children}
    </div>
  </div>
);

const LayerModal = ({
  onClose, onSave, initialData
}: {
  onClose: () => void;
  onSave: (name: string, description: string, icon?: string, color?: string) => void;
  initialData?: { name: string; description: string; icon?: string; color?: string };
}) => {
  const [name, setName] = useState(initialData?.name ?? '');
  const [description, setDescription] = useState(initialData?.description ?? '');
  const [icon, setIcon] = useState<string | undefined>(initialData?.icon);
  const [color, setColor] = useState(initialData?.color ?? '');
  const isEditing = initialData !== undefined;
  const handleSave = () => { if (name.trim()) onSave(name.trim(), description.trim(), icon, color || undefined); };
  return (
    <Modal onClose={onClose} title={isEditing ? 'Edit Layer' : 'Add Layer'}>
      <div className="u-form-group">
        <label className="u-form-label">Layer name</label>
        <input
          className="u-form-input"
          type="text"
          placeholder="e.g. Policy, Community, Institutional"
          value={name}
          onChange={e => setName(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSave(); }}
          autoFocus
        />
      </div>
      <div className="u-form-group">
        <label className="u-form-label">Description (optional)</label>
        <input
          className="u-form-input"
          type="text"
          placeholder="Brief description of this layer"
          value={description}
          onChange={e => setDescription(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSave(); }}
        />
      </div>
      <div className="u-form-group">
        <label className="u-form-label">Icon <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional)</span></label>
        <div className="u-icon-picker">
          <button type="button"
            className={`u-icon-picker-item${!icon ? ' u-icon-picker-item--selected' : ''}`}
            onClick={() => setIcon(undefined)} title="None">
            <span style={{ fontSize: '0.7rem', color: '#6B625A' }}>–</span>
          </button>
          {ICON_CATEGORIES.map(cat => (
            <div key={cat} className="u-icon-picker-group">
              <div className="u-icon-picker-category">{cat}</div>
              <div className="u-icon-picker-row">
                {ICON_PALETTE.filter(i => i.category === cat).map(({ name: iconName }) => (
                  <button key={iconName} type="button"
                    className={`u-icon-picker-item${icon === iconName ? ' u-icon-picker-item--selected' : ''}`}
                    onClick={() => setIcon(iconName)} title={iconName}>
                    <span className="material-symbols-outlined" style={{ fontSize: 16 }}>{iconName}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
      <div className="u-form-group">
        <label className="u-form-label">Band color <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional)</span></label>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <input className="u-form-color" type="color" value={color || '#D2BDA3'} onChange={e => setColor(e.target.value)} />
          {color && <button type="button" className="u-btn" style={{ fontSize: '0.7rem', padding: '2px 8px' }} onClick={() => setColor('')}>Clear</button>}
        </div>
      </div>
      <button className="u-btn u-btn--layer u-btn--full" onClick={handleSave} disabled={!name.trim()}>
        {isEditing ? 'Save Layer' : 'Add Layer'}
      </button>
    </Modal>
  );
};

const EventModal = ({
  onClose, onSave, layers, startYear, endYear, yearToPct, initialData, events, defaultLinkedStateIdx
}: {
  onClose: () => void;
  onSave: (data: TimelineEvent, linkedStateIdx?: number) => void;
  layers: Layer[];
  startYear: number;
  endYear: number;
  yearToPct: (year: number) => number;
  initialData?: Partial<TimelineEvent>;
  events: TimelineEvent[];
  defaultLinkedStateIdx?: number;
}) => {
  const midYear = Math.round((startYear + endYear) / 2);
  const eventType = initialData?.type ?? 'state';
  const isNew = !initialData?.label;
  const [label, setLabel]         = useState(initialData?.label       ?? '');
  const [dateLabel, setDateLabel] = useState(initialData?.dateLabel   ?? '');
  const [year, setYear]           = useState(initialData?.year        ?? midYear);
  const [eventEndYear, setEventEndYear] = useState<string>(
    initialData?.endYear !== undefined ? String(initialData.endYear) : ''
  );
  const [layer, setLayer]         = useState(initialData?.layer       ?? 0);
  const [color, setColor]         = useState(initialData?.color       ?? (eventType === 'anchor' ? '#3E3B35' : BG_COLOR));
  const [borderColor, setBorder]  = useState(initialData?.borderColor ?? '#3E3B35');
  const [style, setStyle]         = useState<'normal'|'italic'>(initialData?.style ?? 'normal');

  const statesInLayer = (l: number) =>
    events.map((ev, idx) => ({ ev, idx })).filter(({ ev }) => (ev.type ?? 'state') === 'state' && ev.layer === l);

  const [linkedStateIdx, setLinkedStateIdx] = useState<number | null>(() => {
    if (eventType !== 'anchor' || !isNew) return null;
    return defaultLinkedStateIdx ?? statesInLayer(initialData?.layer ?? 0)[0]?.idx ?? null;
  });

  const handleLayerChange = (newLayer: number) => {
    setLayer(newLayer);
    if (eventType === 'anchor' && isNew) {
      setLinkedStateIdx(statesInLayer(newLayer)[0]?.idx ?? null);
    }
  };

  const handleSave = () => {
    if (!label.trim()) return;
    const parsedEndYear = eventType === 'state' && eventEndYear.trim() !== ''
      ? Number(eventEndYear)
      : undefined;
    // x = midpoint if both years given; addEvent will compute pixel width
    const x = (parsedEndYear !== undefined && parsedEndYear > year)
      ? yearToPct((year + parsedEndYear) / 2)
      : yearToPct(year);
    const yOffset = initialData?.yOffset ?? DEFAULT_Y_OFFSET;
    // Preserve an existing resize-width only when no endYear is active
    const width = parsedEndYear !== undefined ? undefined : initialData?.width;
    onSave(
      { label: label.trim(), year, dateLabel: dateLabel.trim() || undefined, endYear: parsedEndYear, layer, x, yOffset, color, borderColor, style, type: eventType, width, xOffsetPct: initialData?.xOffsetPct },
      eventType === 'anchor' && isNew && linkedStateIdx !== null ? linkedStateIdx : undefined,
    );
  };

  const isState = eventType === 'state';
  const title = initialData?.label
    ? (isState ? 'Edit State' : 'Edit Anchor')
    : (isState ? 'Add State'  : 'Add Anchor');

  const layerStates = statesInLayer(layer);

  return (
    <Modal onClose={onClose} title={title} accentColor="var(--btn-event)">
      <div className="u-form-group">
        <label className="u-form-label">{isState ? 'Title' : 'Label'}</label>
        <input className="u-form-input" type="text" placeholder={isState ? 'State title' : 'Anchor label'} value={label}
          onChange={e => setLabel(e.target.value)} autoFocus />
      </div>
      <div className="u-form-row">
        <div className="u-form-group">
          <label className="u-form-label">{isState ? 'Start Year' : 'Year'}</label>
          <input className="u-form-input" type="number" value={year} min={startYear} max={endYear}
            onChange={e => setYear(Number(e.target.value))} />
        </div>
        <div className="u-form-group">
          <label className="u-form-label">Date label <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional)</span></label>
          <input className="u-form-input" type="text" placeholder={`e.g. "Spring ${year}"`}
            value={dateLabel} onChange={e => setDateLabel(e.target.value)} />
        </div>
      </div>
      <div className="u-form-row">
        {isState ? (
          <div className="u-form-group">
            <label className="u-form-label">End Year <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional)</span></label>
            <input className="u-form-input" type="number" placeholder="—"
              value={eventEndYear} min={year + 1} max={endYear}
              onChange={e => setEventEndYear(e.target.value)} />
          </div>
        ) : (
          <div className="u-form-group">
            <label className="u-form-label">Layer</label>
            <select className="u-form-select" value={layer} onChange={e => handleLayerChange(Number(e.target.value))}>
              {layers.map((l, i) => <option key={i} value={i}>{l.label}</option>)}
            </select>
          </div>
        )}
      </div>
      {isState && (
        <div className="u-form-row">
          <div className="u-form-group">
            <label className="u-form-label">Layer</label>
            <select className="u-form-select" value={layer} onChange={e => handleLayerChange(Number(e.target.value))}>
              {layers.map((l, i) => <option key={i} value={i}>{l.label}</option>)}
            </select>
          </div>
        </div>
      )}
      {!isState && isNew && layerStates.length > 0 && (
        <div className="u-form-group">
          <label className="u-form-label">Link to State</label>
          <select className="u-form-select" value={linkedStateIdx ?? 'none'}
            onChange={e => setLinkedStateIdx(e.target.value === 'none' ? null : Number(e.target.value))}>
            <option value="none">None</option>
            {layerStates.map(({ ev, idx }) => (
              <option key={idx} value={idx}>{ev.label || `State ${idx + 1}`}</option>
            ))}
          </select>
        </div>
      )}
      <div className="u-form-row">
        <div className="u-form-group">
          <label className="u-form-label">{isState ? 'Background' : 'Color'}</label>
          <input className="u-form-color" type="color" value={color} onChange={e => setColor(e.target.value)} />
        </div>
        {isState && (
          <div className="u-form-group">
            <label className="u-form-label">Border</label>
            <input className="u-form-color" type="color" value={borderColor} onChange={e => setBorder(e.target.value)} />
          </div>
        )}
      </div>
      <div className="u-form-group">
        <label className="u-form-label">Style</label>
        <select className="u-form-select" value={style} onChange={e => setStyle(e.target.value as 'normal'|'italic')}>
          <option value="normal">Normal</option>
          <option value="italic">Italic</option>
        </select>
      </div>
      <button className="u-btn u-btn--event u-btn--full" onClick={handleSave} disabled={!label.trim()}>
        {title}
      </button>
    </Modal>
  );
};

