const TopicalEventModal = ({
  onClose, onSave, onDelete, startYear, endYear, eraHint, initialData, eras,
}: {
  onClose: () => void;
  onSave: (data: TopicalEvent) => void;
  onDelete?: () => void;
  startYear: number;
  endYear: number;
  eraHint?: Column;
  initialData?: TopicalEvent;
  eras?: Column[];
}) => {
  const [selectedEraLabel, setSelectedEraLabel] = useState(
    initialData?.eraLabel ?? eraHint?.label ?? ''
  );
  const selectedEra = eras?.find(e => e.label === selectedEraLabel);
  const minYear = selectedEra ? selectedEra.startYear : (eraHint ? eraHint.startYear : startYear);
  const maxYear = selectedEra ? selectedEra.endYear : (eraHint ? eraHint.endYear : endYear);
  const [label, setLabel] = useState(initialData?.label ?? '');
  const [year, setYear]   = useState(initialData?.year ?? minYear);
  const [icon, setIcon]   = useState<string | undefined>(initialData?.icon);
  const isEditing = !!initialData;

  return (
    <Modal onClose={onClose} title={isEditing ? 'Edit Event' : 'Add Event'} accentColor="var(--btn-column)">
      <div className="u-form-group">
        <label className="u-form-label">Label</label>
        <input className="u-form-input" type="text" placeholder="Event label"
          value={label} onChange={e => setLabel(e.target.value)} autoFocus />
      </div>
      {eras && eras.length > 0 && (
        <div className="u-form-group">
          <label className="u-form-label">Era</label>
          <select className="u-form-input" value={selectedEraLabel}
            onChange={e => setSelectedEraLabel(e.target.value)}>
            <option value="">— none —</option>
            {eras.map(era => (
              <option key={era.label} value={era.label}>{era.label}</option>
            ))}
          </select>
        </div>
      )}
      <div className="u-form-group">
        <label className="u-form-label">Year</label>
        <input className="u-form-input" type="number"
          value={year} min={minYear} max={maxYear}
          onChange={e => setYear(Number(e.target.value))} />
      </div>
      <div className="u-form-group">
        <label className="u-form-label">Icon <span style={{ fontWeight: 400, opacity: 0.6 }}>(optional)</span></label>
        <div className="u-icon-picker">
          <button type="button"
            className={`u-icon-picker-item${!icon ? ' u-icon-picker-item--selected' : ''}`}
            onClick={() => setIcon(undefined)} title="None">
            <span style={{ fontSize: '0.7rem', color: '#6B625A' }}>–</span>
          </button>
          {ICON_CATEGORIES.map(cat => (
            <div key={cat} className="u-icon-picker-group">
              <div className="u-icon-picker-category">{cat}</div>
              <div className="u-icon-picker-row">
                {ICON_PALETTE.filter(i => i.category === cat).map(({ name: iconName }) => (
                  <button key={iconName} type="button"
                    className={`u-icon-picker-item${icon === iconName ? ' u-icon-picker-item--selected' : ''}`}
                    onClick={() => setIcon(iconName)} title={iconName}>
                    <span className="material-symbols-outlined" style={{ fontSize: 16 }}>{iconName}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
      <button className="u-btn u-btn--column u-btn--full"
        onClick={() => label.trim() && onSave({ label: label.trim(), year, icon, eraLabel: selectedEraLabel || undefined })}
        disabled={!label.trim()}>
        {isEditing ? 'Save Event' : 'Add Event'}
      </button>
      {isEditing && onDelete && (
        <button className="u-btn u-btn--danger u-btn--full" style={{ marginTop: 8 }}
          onClick={onDelete}>
          Delete Event
        </button>
      )}
    </Modal>
  );
};

